const express = require('express');
const app = express();
app.use(express.json());

let playerData = {}; // Example storage, replace with actual database in production

app.post('/complete-level', (req, res) => {
    const { playerId, levelId, score, time } = req.body;
    
    if (!playerId || !levelId || !score || !time) {
        return res.status(400).send('Invalid data');
    }

    if (!playerData[playerId]) {
        playerData[playerId] = { levels: {}, rewards: [] };
    }
    
    playerData[playerId].levels[levelId] = { score, time };

    res.send('Level completed');
});

app.post('/claim-reward', (req, res) => {
    const { playerId, levelId } = req.body;

    if (!playerId || !levelId || !playerData[playerId]?.levels[levelId]) {
        return res.status(400).send('Invalid request');
    }
    
    const { score, time } = playerData[playerId].levels[levelId];
    
    let reward = calculateReward(score, time);
    playerData[playerId].rewards.push(reward);
    
    res.send({ reward });
});

function calculateReward(score, time) {
    return (score / time) * 100; // Example reward calculation, adjust as needed
}

app.listen(3000, () => {
    console.log('API server running on port 3000');
});